(window.webpackJsonp=window.webpackJsonp||[]).push([[28],{655:function(n,t){n.exports='\x3c!-- \ntitle: 10-Linux基础\nsort: \n--\x3e \n# Linux 基础\n\n## 文件和目录\n\n- /bin\t二进制文件\n- /home 用户目录\n\n\n\n## 创建文件\n\n- mkdir -p 递归创建文件夹(parents)\n- touch 创建文件\n- gedit 打开文件编辑   \n- funny\n\n  > mkdir a/b/c/d/e/f a/b/c/d/f  a/b/c/e a/b/d a/c b\n\n\n\n## 删除文件\n\n- rm 删除命令\n  > -i\t确认删除\n  >\n  > -f\t无需确认(force)\n  >\n  > -r\t删除文件夹\n  \n  \n\n## 拷贝文件\n\n- cp -> copy\n\n  复制文件\n\n  > -i\t交互模式删除\n  >\n  > -f\t强制覆盖\n  >\n  > -v\t显示过程(verbose)\n  >\n  > -r\t拷贝目录(recursive)\n  >\n  > -a\t拷贝原有属性(attric)\n\n\n\n## 移动文件\n\n+ mv\n\n  移动文件 \n\n  > -ifv\t同上\n  >\n  > -r\t\t 不需要\n\n\n\n## 其他命令\n\n1. ### Tab键\n\n2. ### Which\n\n3. ### Ctrl+C\n\n4. ### cal\n\n   > -3\t显示三个月\n   >\n   > -y\t显示一年\n   >\n   > -j\t一年中第xx天\n   >\n   > 1997\t显示1997年日历\n\n5. ### date\n\n   > "+%Y-%m-%d %H:%M:%S "\n   >\n   > %F\t日期\n   >\n   > %T\t时间\n\n6. ### history \n\n   ！序号\t执行该命令  \n\n7. ### cat \n\n   > -n\t编号(number)\n   >\n   > -b\t编号（非空行）\n   >\n   > -s\t多空行只显示一行\n\n8. ### more\n\n   windows中也有\n\n   > +数字\t从该行开始显示\n   >\n   > -p\t\t\t先清屏再显示\n\n   ### 快捷键\n\n   > 空格\t下一屏\n   >\n   > 回车\t下一行\n   >\n   > f/b\t\t上一页/下一页\n\n   \n'}}]);